mapper.select:
SELECT * FROM saf.tn_saf_airprt_fuel
WHERE airprt_cd = #{airprtId} AND rprt_yr = #{rprtYr} AND oprtr_id = #{oprtrId}
  AND use_end_dt > NOW()

SELECT * FROM saf.tn_saf_airprt_fuel
WHERE use_end_dt > NOW()
AND oprtr_id = #{oprtrId}
AND rprt_yr = #{rprtYr}
ORDER BY rprt_yr DESC, airprt_cd

mapper.update:
UPDATE saf.tn_saf_airprt_fuel
SET use_end_dt       = NOW() - INTERVAL '1 minute',
    last_chg_dt      = NOW(),
    last_chg_user_id = #{userId}
WHERE airprt_cd = #{airprtId} AND rprt_yr = #{rprtYr} AND oprtr_id = #{oprtrId}
  AND use_end_dt > NOW()
